 1→import { Atom } from "@effect-atom/atom"
 2→import { Option } from "effect"
 3→import { ContractAddress, TxHash } from "../services/types"
 4→import { DEFAULT_NETWORK } from "../config/networks"
 5→import type { NetworkId } from "../config/networks"
 6→
 7→export type { NetworkId }
 8→
 9→export type DeployStep =
10→  | { step: "idle" }
11→  | { step: "generating-keypair" }
12→  | { step: "packing" }
13→  | { step: "computing-address" }
14→  | { step: "awaiting-funds"; address: ContractAddress }
15→  | { step: "deploying"; address: ContractAddress }
16→  | { step: "deployed"; address: ContractAddress; txHash: TxHash }
17→  | { step: "error"; message: string }
18→
19→export const deployStepAtom = Atom.make<DeployStep>({ step: "idle" }).pipe(
20→  Atom.keepAlive,
21→)
22→
23→export const deployedAddressAtom = Atom.make<Option.Option<ContractAddress>>(Option.none()).pipe(
24→  Atom.keepAlive,
25→)
26→
27→export const deployTxHashAtom = Atom.make<Option.Option<TxHash>>(Option.none()).pipe(
28→  Atom.keepAlive,
29→)
30→
31→const NETWORK_STORAGE_KEY = "falcon-demo-network"
32→
33→function readStoredNetwork(): NetworkId {
34→  try {
35→    if (typeof window === "undefined" || typeof localStorage === "undefined") {
36→      return DEFAULT_NETWORK
37→    }
38→    const stored = localStorage.getItem(NETWORK_STORAGE_KEY)
39→    return stored === "mainnet" ? "mainnet" : DEFAULT_NETWORK
40→  } catch {
41→    return DEFAULT_NETWORK
42→  }
43→}
44→
45→export const networkAtom = Atom.make<NetworkId>(readStoredNetwork()).pipe(
46→  Atom.keepAlive,
47→)
48→
49→export { NETWORK_STORAGE_KEY }
50→

