  1→/// Falcon-512 Account Component
  2→///
  3→/// Implements Starknet account abstraction using Falcon-512 post-quantum signatures.
  4→/// Modeled on OpenZeppelin's AccountComponent but replaces ECDSA with Falcon verification.
  5→#[starknet::component]
  6→pub mod FalconAccountComponent {
  7→    use core::num::traits::Zero;
  8→    use falcon::falcon::verify_packed;
  9→    use falcon::hash_to_point::PoseidonHashToPoint;
 10→    use falcon::packing::PackedPolynomial512;
 11→    use falcon::types::PackedFalconSignatureWithHint;
 12→    use openzeppelin_interfaces::account::accounts as interface;
 13→    use openzeppelin_introspection::src5::SRC5Component;
 14→    use openzeppelin_introspection::src5::SRC5Component::{
 15→        InternalTrait as SRC5InternalTrait, SRC5Impl,
 16→    };
 17→    use openzeppelin_utils::execution::execute_single_call;
 18→    use starknet::account::Call;
 19→    use starknet::storage::{StoragePointerReadAccess, StoragePointerWriteAccess};
 20→    use crate::utils::is_tx_version_valid;
 21→
 22→    #[storage]
 23→    pub struct Storage {
 24→        pub pk_0: felt252,
 25→        pub pk_1: felt252,
 26→        pub pk_2: felt252,
 27→        pub pk_3: felt252,
 28→        pub pk_4: felt252,
 29→        pub pk_5: felt252,
 30→        pub pk_6: felt252,
 31→        pub pk_7: felt252,
 32→        pub pk_8: felt252,
 33→        pub pk_9: felt252,
 34→        pub pk_10: felt252,
 35→        pub pk_11: felt252,
 36→        pub pk_12: felt252,
 37→        pub pk_13: felt252,
 38→        pub pk_14: felt252,
 39→        pub pk_15: felt252,
 40→        pub pk_16: felt252,
 41→        pub pk_17: felt252,
 42→        pub pk_18: felt252,
 43→        pub pk_19: felt252,
 44→        pub pk_20: felt252,
 45→        pub pk_21: felt252,
 46→        pub pk_22: felt252,
 47→        pub pk_23: felt252,
 48→        pub pk_24: felt252,
 49→        pub pk_25: felt252,
 50→        pub pk_26: felt252,
 51→        pub pk_27: felt252,
 52→        pub pk_28: felt252,
 53→    }
 54→
 55→    #[event]
 56→    #[derive(Drop, starknet::Event)]
 57→    pub enum Event {}
 58→
 59→    pub mod Errors {
 60→        pub const INVALID_CALLER: felt252 = 'Account: invalid caller';
 61→        pub const INVALID_SIGNATURE: felt252 = 'Account: invalid signature';
 62→        pub const INVALID_TX_VERSION: felt252 = 'Account: invalid tx version';
 63→    }
 64→
 65→    //
 66→    // External
 67→    //
 68→
 69→    #[embeddable_as(SRC6Impl)]
 70→    impl SRC6<
 71→        TContractState,
 72→        +HasComponent<TContractState>,
 73→        +SRC5Component::HasComponent<TContractState>,
 74→        +Drop<TContractState>,
 75→    > of interface::ISRC6<ComponentState<TContractState>> {
 76→        fn __execute__(self: @ComponentState<TContractState>, calls: Array<Call>) {
 77→            let sender = starknet::get_caller_address();
 78→            assert(sender.is_zero(), Errors::INVALID_CALLER);
 79→            assert(is_tx_version_valid(), Errors::INVALID_TX_VERSION);
 80→            for call in calls.span() {
 81→                execute_single_call(call);
 82→            }
 83→        }
 84→
 85→        fn __validate__(self: @ComponentState<TContractState>, calls: Array<Call>) -> felt252 {
 86→            self.validate_transaction()
 87→        }
 88→
 89→        fn is_valid_signature(
 90→            self: @ComponentState<TContractState>, hash: felt252, signature: Array<felt252>,
 91→        ) -> felt252 {
 92→            if self._is_valid_signature(hash, signature.span()) {
 93→                starknet::VALIDATED
 94→            } else {
 95→                0
 96→            }
 97→        }
 98→    }
 99→
100→    #[embeddable_as(DeclarerImpl)]
101→    impl Declarer<
102→        TContractState,
103→        +HasComponent<TContractState>,
104→        +SRC5Component::HasComponent<TContractState>,
105→        +Drop<TContractState>,
106→    > of interface::IDeclarer<ComponentState<TContractState>> {
107→        fn __validate_declare__(
108→            self: @ComponentState<TContractState>, class_hash: felt252,
109→        ) -> felt252 {
110→            self.validate_transaction()
111→        }
112→    }
113→
114→    //
115→    // Internal
116→    //
117→
118→    #[generate_trait]
119→    pub impl InternalImpl<
120→        TContractState,
121→        +HasComponent<TContractState>,
122→        impl SRC5: SRC5Component::HasComponent<TContractState>,
123→        +Drop<TContractState>,
124→    > of InternalTrait<TContractState> {
125→        /// Initializes the account with a packed Falcon public key.
126→        /// Registers the ISRC6 interface.
127→        fn initializer(ref self: ComponentState<TContractState>, pk: PackedPolynomial512) {
128→            let mut src5_component = get_dep_component_mut!(ref self, SRC5);
129→            src5_component.register_interface(interface::ISRC6_ID);
130→            self.write_packed_pk(pk);
131→        }
132→
133→        /// Validates the signature for the current transaction.
134→        /// Returns the short string 'VALID' if valid, otherwise reverts.
135→        fn validate_transaction(self: @ComponentState<TContractState>) -> felt252 {
136→            let tx_info = starknet::get_tx_info().unbox();
137→            let tx_hash = tx_info.transaction_hash;
138→            let signature = tx_info.signature;
139→            assert(self._is_valid_signature(tx_hash, signature), Errors::INVALID_SIGNATURE);
140→            starknet::VALIDATED
141→        }
142→
143→        /// Returns whether the given signature is valid for the given hash.
144→        fn _is_valid_signature(
145→            self: @ComponentState<TContractState>, hash: felt252, signature: Span<felt252>,
146→        ) -> bool {
147→            let mut sig_span = signature;
148→            let sig: PackedFalconSignatureWithHint = match Serde::deserialize(ref sig_span) {
149→                Option::Some(s) => s,
150→                Option::None => { return false; },
151→            };
152→            let pk = self.read_packed_pk();
153→            let message = array![hash];
154→            verify_packed::<PoseidonHashToPoint>(@pk, sig, message.span())
155→        }
156→
157→        /// Returns the packed public key.
158→        fn get_public_key(self: @ComponentState<TContractState>) -> PackedPolynomial512 {
159→            self.read_packed_pk()
160→        }
161→
162→        /// Reads the 29 packed PK slots from storage into a PackedPolynomial512.
163→        fn read_packed_pk(self: @ComponentState<TContractState>) -> PackedPolynomial512 {
164→            PackedPolynomial512 {
165→                s0: self.pk_0.read(),
166→                s1: self.pk_1.read(),
167→                s2: self.pk_2.read(),
168→                s3: self.pk_3.read(),
169→                s4: self.pk_4.read(),
170→                s5: self.pk_5.read(),
171→                s6: self.pk_6.read(),
172→                s7: self.pk_7.read(),
173→                s8: self.pk_8.read(),
174→                s9: self.pk_9.read(),
175→                s10: self.pk_10.read(),
176→                s11: self.pk_11.read(),
177→                s12: self.pk_12.read(),
178→                s13: self.pk_13.read(),
179→                s14: self.pk_14.read(),
180→                s15: self.pk_15.read(),
181→                s16: self.pk_16.read(),
182→                s17: self.pk_17.read(),
183→                s18: self.pk_18.read(),
