  1→//! Base-Q polynomial packing for storage-efficient Falcon public keys.
  2→//!
  3→//! Packs 512 Zq values into 29 felt252 slots using base Q=12289 encoding:
  4→//!   felt252 = pack_9(v0..v8) + pack_9(v9..v17) * 2^128
  5→//!
  6→//! DivRem by Q gives RemT = Zq directly — zero downcasts in the hot path.
  7→
  8→use corelib_imports::bounded_int::bounded_int::{add, mul};
  9→use corelib_imports::bounded_int::{
 10→    AddHelper, BoundedInt, DivRemHelper, MulHelper, bounded_int_div_rem, downcast, upcast,
 11→};
 12→use falcon::zq::{NZ_Q, QConst, Q_CONST, Zq};
 13→
 14→// =============================================================================
 15→// Constants
 16→// =============================================================================
 17→
 18→/// Number of Zq values per u128 half (Q^9 < 2^128)
 19→const VALS_PER_U128: usize = 9;
 20→
 21→/// Number of Zq values per felt252 (two u128 halves)
 22→const VALS_PER_FELT: usize = 18;
 23→
 24→/// Total felt252 slots for 512 values: ceil(512/18) = 29
 25→const PACKED_SLOTS: usize = 29;
 26→
 27→/// 2^128 as felt252 for combining u128 halves
 28→const TWO_POW_128: felt252 = 0x100000000000000000000000000000000;
 29→
 30→// =============================================================================
 31→// Accumulator type chain: AccN max = Q^(N+1) - 1
 32→// Shared between Horner packing and DivRem unpacking.
 33→// Acc0 = Zq (reused from zq.cairo)
 34→// =============================================================================
 35→
 36→type Acc0 = Zq; // BoundedInt<0, 12288>
 37→type Acc1 = BoundedInt<0, 151019520>;
 38→type Acc2 = BoundedInt<0, 1855878893568>;
 39→type Acc3 = BoundedInt<0, 22806895723069440>;
 40→type Acc4 = BoundedInt<0, 280273941540800360448>;
