260→/// Unpack a u128 into `count` Zq values using iterated DivRem by Q.
261→fn unpack_9(packed: u128, count: usize, ref output: Array<Zq>) {
262→    if count == 0 {
263→        return;
264→    }
265→    let acc8: Acc8 = downcast(packed).expect('invalid packed value');
266→    let (acc7, r0) = bounded_int_div_rem(acc8, NZ_Q);
267→    output.append(r0);
268→    if count == 1 {
269→        return;
270→    }
271→    let (acc6, r1) = bounded_int_div_rem(acc7, NZ_Q);
272→    output.append(r1);
273→    if count == 2 {
274→        return;
275→    }
276→    let (acc5, r2) = bounded_int_div_rem(acc6, NZ_Q);
277→    output.append(r2);
278→    if count == 3 {
279→        return;
280→    }
281→    let (acc4, r3) = bounded_int_div_rem(acc5, NZ_Q);
282→    output.append(r3);
283→    if count == 4 {
284→        return;
285→    }
286→    let (acc3, r4) = bounded_int_div_rem(acc4, NZ_Q);
287→    output.append(r4);
288→    if count == 5 {
289→        return;
290→    }
291→    let (acc2, r5) = bounded_int_div_rem(acc3, NZ_Q);
292→    output.append(r5);
293→    if count == 6 {
294→        return;
295→    }
296→    let (acc1, r6) = bounded_int_div_rem(acc2, NZ_Q);
297→    output.append(r6);
298→    if count == 7 {
299→        return;
300→    }
301→    let (acc0, r7) = bounded_int_div_rem(acc1, NZ_Q);
302→    output.append(r7);
303→    if count == 8 {
304→        return;
305→    }
306→    output.append(acc0);
307→}
308→
309→/// Unpack a u128 into exactly 9 Zq values. No count checks.
310→fn unpack_9_full(packed: u128, ref output: Array<Zq>) {
311→    let acc8: Acc8 = downcast(packed).expect('bad pack');
312→    let (acc7, r0) = bounded_int_div_rem(acc8, NZ_Q);
313→    output.append(r0);
314→    let (acc6, r1) = bounded_int_div_rem(acc7, NZ_Q);
315→    output.append(r1);
316→    let (acc5, r2) = bounded_int_div_rem(acc6, NZ_Q);
317→    output.append(r2);
318→    let (acc4, r3) = bounded_int_div_rem(acc5, NZ_Q);
319→    output.append(r3);
320→    let (acc3, r4) = bounded_int_div_rem(acc4, NZ_Q);
321→    output.append(r4);
322→    let (acc2, r5) = bounded_int_div_rem(acc3, NZ_Q);
323→    output.append(r5);
324→    let (acc1, r6) = bounded_int_div_rem(acc2, NZ_Q);
325→    output.append(r6);
326→    let (acc0, r7) = bounded_int_div_rem(acc1, NZ_Q);
327→    output.append(r7);
328→    output.append(acc0);
329→}
330→
331→/// Unpack a u128 into exactly 8 Zq values (7 div_rems + final quotient).
332→fn unpack_8(packed: u128, ref output: Array<Zq>) {
333→    let acc7: Acc7 = downcast(packed).expect('bad pack');
334→    let (acc6, r0) = bounded_int_div_rem(acc7, NZ_Q);
335→    output.append(r0);
336→    let (acc5, r1) = bounded_int_div_rem(acc6, NZ_Q);
337→    output.append(r1);
338→    let (acc4, r2) = bounded_int_div_rem(acc5, NZ_Q);
339→    output.append(r2);
340→    let (acc3, r3) = bounded_int_div_rem(acc4, NZ_Q);
341→    output.append(r3);
342→    let (acc2, r4) = bounded_int_div_rem(acc3, NZ_Q);
343→    output.append(r4);
344→    let (acc1, r5) = bounded_int_div_rem(acc2, NZ_Q);
345→    output.append(r5);
346→    let (acc0, r6) = bounded_int_div_rem(acc1, NZ_Q);
347→    output.append(r6);
348→    output.append(acc0);
349→}
350→
351→/// Pack 512 Zq values into 29 felt252 slots.
352→/// Each slot encodes up to 18 values: pack_9(lo) + pack_9(hi) * 2^128.
353→pub fn pack_public_key(values: Span<Zq>) -> Array<felt252> {
354→    assert!(values.len() == 512, "expected 512 values");
355→    let mut result: Array<felt252> = array![];
356→    let mut offset: usize = 0;
357→    // 28 full slots: 9 lo + 9 hi = 18 values each (504 total)
358→    while offset != 504 {
359→        let lo_felt: felt252 = pack_9(values.slice(offset, 9)).into();
360→        let hi_felt: felt252 = pack_9(values.slice(offset + 9, 9)).into();
361→        result.append(lo_felt + hi_felt * TWO_POW_128);
362→        offset += 18;
363→    }
364→    // Last slot: 8 remaining values in low half only
365→    result.append(pack_9(values.slice(504, 8)).into());
366→    result
367→}
368→
369→/// Unpack 29 felt252 slots back to 512 Zq values.
370→pub fn unpack_public_key(packed: Span<felt252>) -> Array<Zq> {
371→    let mut output: Array<Zq> = array![];
372→    let mut packed = packed;
373→    // 28 full slots: 9 lo + 9 hi = 18 values each (504 total)
374→    let mut i: usize = 0;
375→    while i != 28 {
376→        let val_u256: u256 = (*packed.pop_front().unwrap()).into();
377→        unpack_9_full(val_u256.low, ref output);
378→        unpack_9_full(val_u256.high, ref output);
379→        i += 1;
