  1→//! Poseidon hash_to_point for Falcon-512.
  2→//!
  3→//! Produces 512 Zq coefficients from (message, salt) using:
  4→//! - poseidon_hash_span(message || salt) -> single felt252 seed
  5→//! - Squeeze: 22 hades_permutations, base-Q extraction (12 Zq per felt252)
  6→//!
  7→//! Security: each coefficient comes from reducing a >=50-bit value mod Q.
  8→//! Per Renyi analysis (scripts/renyi.md), this gives <=0.37 bits security loss.
  9→
 10→use core::poseidon::{hades_permutation, poseidon_hash_span};
 11→use corelib_imports::bounded_int::{BoundedInt, DivRemHelper, bounded_int_div_rem, downcast};
 12→use falcon::types::HashToPoint;
 13→use falcon::zq::{NZ_Q, QConst, Zq};
 14→
 15→// =============================================================================
 16→// LOW extraction chain (from u128, 128 bits -> 6 Zq)
 17→// Starting type: u128 = BoundedInt<0, 2^128-1>
 18→// Each DivRem by Q removes ~13.585 bits. 6 safe coefficients (input >= 50 bits).
 19→// =============================================================================
 20→
 21→type ExtractLQ1 = BoundedInt<0, 27689996494502275487295516920153650>;
 22→type ExtractLQ2 = BoundedInt<0, 2253234314793903123711898195146>;
 23→type ExtractLQ3 = BoundedInt<0, 183353756594833031468133956>;
 24→type ExtractLQ4 = BoundedInt<0, 14920152705251284194656>;
 25→type ExtractLQ5 = BoundedInt<0, 1214106331292317047>;
 26→type ExtractLQ6 = BoundedInt<0, 98796186125178>; // discarded (~47 bits)
 27→
 28→impl DivRemU128ByQ of DivRemHelper<u128, QConst> {
 29→    type DivT = ExtractLQ1;
 30→    type RemT = Zq;
 31→}
 32→
 33→impl DivRemLQ1ByQ of DivRemHelper<ExtractLQ1, QConst> {
 34→    type DivT = ExtractLQ2;
 35→    type RemT = Zq;
 36→}
 37→
 38→impl DivRemLQ2ByQ of DivRemHelper<ExtractLQ2, QConst> {
 39→    type DivT = ExtractLQ3;
 40→    type RemT = Zq;
 41→}
 42→
 43→impl DivRemLQ3ByQ of DivRemHelper<ExtractLQ3, QConst> {
 44→    type DivT = ExtractLQ4;
 45→    type RemT = Zq;
 46→}
 47→
 48→impl DivRemLQ4ByQ of DivRemHelper<ExtractLQ4, QConst> {
 49→    type DivT = ExtractLQ5;
 50→    type RemT = Zq;
 51→}
 52→
 53→impl DivRemLQ5ByQ of DivRemHelper<ExtractLQ5, QConst> {
 54→    type DivT = ExtractLQ6;
 55→    type RemT = Zq;
 56→}
 57→
 58→// =============================================================================
 59→// HIGH extraction chain (from FeltHigh, 124 bits -> 6 Zq)
 60→// high_max = (StarkPrime - 1) >> 128 = 10633823966279327296825105735305134080
 61→// Tighter bound than u128 -> separate type chain with exact quotient bounds.
 62→// =============================================================================
 63→
 64→type FeltHigh = BoundedInt<0, 10633823966279327296825105735305134080>;
 65→
 66→type ExtractHQ1 = BoundedInt<0, 865312390453196134496306105891865>;
 67→type ExtractHQ2 = BoundedInt<0, 70413572337309474692514126933>;
 68→type ExtractHQ3 = BoundedInt<0, 5729804893588532402352846>;
 69→type ExtractHQ4 = BoundedInt<0, 466254772039102644833>;
 70→type ExtractHQ5 = BoundedInt<0, 37940822852884908>;
 71→type ExtractHQ6 = BoundedInt<0, 3087380816411>; // discarded (~42 bits)
 72→
 73→impl DivRemFeltHighByQ of DivRemHelper<FeltHigh, QConst> {
 74→    type DivT = ExtractHQ1;
 75→    type RemT = Zq;
 76→}
 77→
 78→impl DivRemHQ1ByQ of DivRemHelper<ExtractHQ1, QConst> {
 79→    type DivT = ExtractHQ2;
 80→    type RemT = Zq;
 81→}
 82→
 83→impl DivRemHQ2ByQ of DivRemHelper<ExtractHQ2, QConst> {
 84→    type DivT = ExtractHQ3;
 85→    type RemT = Zq;
 86→}
 87→
 88→impl DivRemHQ3ByQ of DivRemHelper<ExtractHQ3, QConst> {
 89→    type DivT = ExtractHQ4;
 90→    type RemT = Zq;
 91→}
 92→
 93→impl DivRemHQ4ByQ of DivRemHelper<ExtractHQ4, QConst> {
 94→    type DivT = ExtractHQ5;
 95→    type RemT = Zq;
 96→}
 97→
 98→impl DivRemHQ5ByQ of DivRemHelper<ExtractHQ5, QConst> {
 99→    type DivT = ExtractHQ6;
100→    type RemT = Zq;
101→}
102→
103→// =============================================================================
104→// Extraction functions: base-Q digit extraction via DivRem chains
105→// =============================================================================
106→
107→/// Extract 6 Zq coefficients from a u128 value via successive DivRem by Q.
108→fn extract_6_from_low(value: u128, ref coeffs: Array<Zq>) {
109→    let (q1, r0) = bounded_int_div_rem(value, NZ_Q);
110→    coeffs.append(r0);
111→    let (q2, r1) = bounded_int_div_rem(q1, NZ_Q);
112→    coeffs.append(r1);
113→    let (q3, r2) = bounded_int_div_rem(q2, NZ_Q);
114→    coeffs.append(r2);
115→    let (q4, r3) = bounded_int_div_rem(q3, NZ_Q);
116→    coeffs.append(r3);
117→    let (q5, r4) = bounded_int_div_rem(q4, NZ_Q);
118→    coeffs.append(r4);
119→    let (_q6, r5) = bounded_int_div_rem(q5, NZ_Q);
120→    coeffs.append(r5);
121→}
122→
123→/// Extract 6 Zq coefficients from the high part of a felt252 (FeltHigh).
124→fn extract_6_from_high(value: FeltHigh, ref coeffs: Array<Zq>) {
125→    let (q1, r0) = bounded_int_div_rem(value, NZ_Q);
126→    coeffs.append(r0);
127→    let (q2, r1) = bounded_int_div_rem(q1, NZ_Q);
128→    coeffs.append(r1);
129→    let (q3, r2) = bounded_int_div_rem(q2, NZ_Q);
130→    coeffs.append(r2);
131→    let (q4, r3) = bounded_int_div_rem(q3, NZ_Q);
132→    coeffs.append(r3);
133→    let (q5, r4) = bounded_int_div_rem(q4, NZ_Q);
134→    coeffs.append(r4);
135→    let (_q6, r5) = bounded_int_div_rem(q5, NZ_Q);
136→    coeffs.append(r5);
137→}
138→
139→/// Extract 2 Zq coefficients from the high part of a felt252 (FeltHigh).
140→/// Used for the final partial squeeze round (512 = 21*24 + 6 + 2).
141→fn extract_2_from_high(value: FeltHigh, ref coeffs: Array<Zq>) {
142→    let (q1, r0) = bounded_int_div_rem(value, NZ_Q);
143→    coeffs.append(r0);
144→    let (_q2, r1) = bounded_int_div_rem(q1, NZ_Q);
145→    coeffs.append(r1);
146→}
147→
148→/// Extract 12 Zq coefficients from a felt252: 6 from low u128, 6 from high FeltHigh.
149→fn extract_12_from_felt252(value: felt252, ref coeffs: Array<Zq>) {
150→    let val_u256: u256 = value.into();
151→    extract_6_from_low(val_u256.low, ref coeffs);
152→    let high_bounded: FeltHigh = downcast(val_u256.high).expect('high exceeds FeltHigh');
153→    extract_6_from_high(high_bounded, ref coeffs);
154→}
155→
156→/// Extract 8 Zq coefficients from a felt252: 6 from low u128, 2 from high FeltHigh.
157→/// Used for the final partial squeeze round to reach exactly 512 coefficients.
158→fn extract_8_from_felt252(value: felt252, ref coeffs: Array<Zq>) {
159→    let val_u256: u256 = value.into();
160→    extract_6_from_low(val_u256.low, ref coeffs);
161→    let high_bounded: FeltHigh = downcast(val_u256.high).expect('high exceeds FeltHigh');
162→    extract_2_from_high(high_bounded, ref coeffs);
163→}
164→
165→// =============================================================================
166→// HashToPoint implementation using Poseidon
167→// =============================================================================
168→
169→#[derive(Drop)]
170→pub struct PoseidonHashToPoint {}
171→
172→pub impl PoseidonHashToPointImpl of HashToPoint<PoseidonHashToPoint> {
173→    fn hash_to_point(message: Span<felt252>, salt: Span<felt252>) -> Array<Zq> {
174→        // Absorb: poseidon_hash_span(message || salt) -> single felt252 seed
175→        let mut input: Array<felt252> = array![];
176→        for m in message {
177→            input.append(*m);
178→        }
179→        for s in salt {
180→            input.append(*s);
181→        }
182→        let seed = poseidon_hash_span(input.span());
183→
184→        // Squeeze: 21 full rounds (504 coefficients) + 1 partial round (8 coefficients)
185→        let (mut s0, mut s1, mut s2): (felt252, felt252, felt252) = (seed, 0, 0);
186→        let mut coeffs: Array<Zq> = array![];
187→
188→        // 21 full rounds: extract 24 coefficients each (12 from s0, 12 from s1)
189→        let mut round: u32 = 0;
190→        while round != 21 {
191→            let (ns0, ns1, ns2) = hades_permutation(s0, s1, s2);
192→            s0 = ns0;
193→            s1 = ns1;
194→            s2 = ns2;
195→            extract_12_from_felt252(s0, ref coeffs);
196→            extract_12_from_felt252(s1, ref coeffs);
197→            round += 1;
198→        }
199→
200→        // Final round: extract 8 from s0 only (6 from low + 2 from high)
201→        let (ns0, _, _) = hades_permutation(s0, s1, s2);
202→        extract_8_from_felt252(ns0, ref coeffs);
203→
204→        coeffs
205→    }
206→}
