import { Atom } from "@effect-atom/atom"
import { Option } from "effect"
import { ContractAddress, TxHash } from "../services/types"
import { DEFAULT_NETWORK } from "../config/networks"
import type { NetworkId } from "../config/networks"

export type { NetworkId }

export type DeployStep =
  | { step: "idle" }
  | { step: "generating-keypair" }
  | { step: "packing" }
  | { step: "computing-address" }
  | { step: "awaiting-funds"; address: ContractAddress }
  | { step: "deploying"; address: ContractAddress }
  | { step: "deployed"; address: ContractAddress; txHash: TxHash }
  | { step: "error"; message: string }

export const deployStepAtom = Atom.make<DeployStep>({ step: "idle" }).pipe(
  Atom.keepAlive,
)

export const deployedAddressAtom = Atom.make<Option.Option<ContractAddress>>(Option.none()).pipe(
  Atom.keepAlive,
)

export const deployTxHashAtom = Atom.make<Option.Option<TxHash>>(Option.none()).pipe(
  Atom.keepAlive,
)

const NETWORK_STORAGE_KEY = "falcon-demo-network"

function readStoredNetwork(): NetworkId {
  try {
    if (typeof window === "undefined" || typeof localStorage === "undefined") {
      return DEFAULT_NETWORK
    }
    const stored = localStorage.getItem(NETWORK_STORAGE_KEY)
    return stored === "mainnet" ? "mainnet" : DEFAULT_NETWORK
  } catch {
    return DEFAULT_NETWORK
  }
}

export const networkAtom = Atom.make<NetworkId>(readStoredNetwork()).pipe(
  Atom.keepAlive,
)

export { NETWORK_STORAGE_KEY }

import { Atom } from "@effect-atom/atom"
import { Option } from "effect"
import type { FalconKeypair, FalconSignatureResult, PackedPublicKey, VerificationStep } from "../services/types"

export const wasmStatusAtom = Atom.make<"loading" | "ready" | "error">("loading").pipe(
  Atom.keepAlive,
)

export const keypairAtom = Atom.make<Option.Option<FalconKeypair>>(Option.none()).pipe(
  Atom.keepAlive,
)

export const signatureAtom = Atom.make<Option.Option<FalconSignatureResult>>(Option.none())

export const packedKeyAtom = Atom.make<Option.Option<PackedPublicKey>>(Option.none())

export const verificationStepAtom = Atom.make<VerificationStep>({ step: "idle" })

export const messageAtom = Atom.make("")

import { Context, Effect, Layer } from "effect"
import { WasmLoadError } from "./errors"

// ---------------------------------------------------------------------------
// WasmModule interface
// ---------------------------------------------------------------------------

export interface WasmModule {
  readonly keygen: (seed: Uint8Array) => { sk: Uint8Array; vk: Uint8Array }
  readonly sign: (
    skBytes: Uint8Array,
    message: Uint8Array,
    salt: Uint8Array,
  ) => {
    signature: Uint8Array
    salt: Uint8Array
  }
  readonly verify: (
    vkBytes: Uint8Array,
    message: Uint8Array,
    signature: Uint8Array,
  ) => boolean
  readonly create_verification_hint: (
    s1: Int32Array,
    pkNtt: Int32Array,
  ) => Uint16Array
  readonly pack_public_key_wasm: (pkNtt: Uint16Array) => string[]
  readonly public_key_length: () => number
  readonly salt_length: () => number
}

// ---------------------------------------------------------------------------
// Runtime type validation — no `as any` or `as unknown as WasmModule`
// ---------------------------------------------------------------------------

/**
 * Runtime guard that checks every method in the WasmModule interface exists
 * and is a function. Returns true only when all seven methods are present.
 *
 * This replaces the unsafe `as unknown as WasmModule` cast that was used in
 * the original implementation.
 *
 * Validation scope: checks that each required key is present and is a
 * function. Function arity and return types cannot be checked without
 * invoking the function (which would have side effects), so only presence
 * and kind are validated here.
 *
 * No type assertions are used: after the null/typeof guard, TypeScript
 * narrows `mod` to `object`, which satisfies `Reflect.get`'s `target:
 * object` parameter — property access is type-safe without any cast.
 */
export function isValidWasmModule(mod: unknown): mod is WasmModule {
  if (mod === null || typeof mod !== "object") return false
  // TypeScript narrows `mod` to `object` here — no type assertion needed.
  // Reflect.get accepts `object` as its first argument directly.
  const methods = [
    "keygen",
    "sign",
    "verify",
    "create_verification_hint",
    "pack_public_key_wasm",
    "public_key_length",
    "salt_length",
  ] as const
  return methods.every((method) => typeof Reflect.get(mod, method) === "function")
}

// ---------------------------------------------------------------------------
// Context.Tag — WasmRuntime service tag
// ---------------------------------------------------------------------------

export class WasmRuntime extends Context.Tag("WasmRuntime")<
  WasmRuntime,
  WasmModule
>() {}

// ---------------------------------------------------------------------------
// Internal load function — uses Effect.fn for automatic span tracing
// ---------------------------------------------------------------------------

const loadWasmModule = Effect.fn("WasmRuntime.load")(function* () {
  const mod = yield* Effect.tryPromise({
    try: async () => {
      // Dynamic import of the WASM JS glue generated by wasm-pack.
      // The `/* webpackIgnore: true */` comment prevents bundlers from
      // trying to resolve this path at build time.
      const modulePath = "/wasm/falcon_rs.js"
      const imported = await import(
        /* webpackIgnore: true */
        modulePath
      )
      // Run the WASM initializer (wasm-pack generates a default export
      // that downloads and instantiates the .wasm binary).
      await imported.default()
      return imported
    },
    catch: (error) =>
      new WasmLoadError({
        message: `Failed to load WASM module: ${String(error)}`,
      }),
  })

  // Runtime validation — replaces unsafe `as unknown as WasmModule`
  if (!isValidWasmModule(mod)) {
    return yield* Effect.fail(
      new WasmLoadError({
        message:
          "WASM module is missing required methods. Expected: keygen, sign, verify, " +
          "create_verification_hint, pack_public_key_wasm, public_key_length, salt_length.",
      }),
    )
  }

  yield* Effect.log("WasmRuntime loaded successfully")
  return mod
})

// ---------------------------------------------------------------------------
// WasmRuntimeLive — Layer that loads and validates the WASM module
//
// Effect's Layer memoization guarantees this effect runs at most once when
// the Layer is provided to the application. There is no mutable global state
// (`let cachedModule`); the singleton guarantee comes from Layer itself.
// ---------------------------------------------------------------------------

export const WasmRuntimeLive = Layer.effect(WasmRuntime, loadWasmModule())

/**
 * HexDisplay — a client component for rendering hex strings and felt252 arrays.
 *
 * Used in the Verification Playground to show the packed public key slots,
 * salt, and signature preview values. Supports:
 * - Single string values
 * - Arrays of strings with optional `maxRows` clamping
 * - Optional `truncate` prop to shorten long hex values
 */

import React from "react"
import { truncateHex } from "./verification-utils"

export interface HexDisplayProps {
  /** Section label shown above the value(s). */
  readonly label: string
  /** A single hex/felt string, or an array of them. */
  readonly value: string | ReadonlyArray<string>
  /**
   * Maximum number of rows to display when `value` is an array.
   * Excess rows are replaced with a "... N more" indicator.
   */
  readonly maxRows?: number
  /**
   * If provided, each displayed value is truncated to
   * `head` characters + "..." + `tail` characters.
   */
  readonly truncate?: { readonly head: number; readonly tail: number }
}

export function HexDisplay(props: HexDisplayProps): React.JSX.Element {
  const { label, value, maxRows, truncate } = props

  const display = (v: string): string =>
    truncate ? truncateHex(v, truncate.head, truncate.tail) : v

  if (typeof value === "string") {
    return (
      <div>
        <span className="block text-sm font-medium text-falcon-muted">
          {label}
        </span>
        <code className="mt-1 block break-all font-mono text-sm text-falcon-accent">
          {display(value)}
        </code>
      </div>
    )
  }

  const items = Array.from(value)
  const shown = maxRows !== undefined ? items.slice(0, maxRows) : items
  const overflow =
    maxRows !== undefined ? Math.max(0, items.length - maxRows) : 0
  const keyCounts = new Map<string, number>()

  return (
    <div>
      <span className="block text-sm font-medium text-falcon-muted">
        {label}
      </span>
      <div className="mt-1 space-y-0.5">
        {shown.map((v) => {
          const nextCount = (keyCounts.get(v) ?? 0) + 1
          keyCounts.set(v, nextCount)
          const stableKey = nextCount === 1 ? v : `${v}-${nextCount}`
          return (
            <code
              key={stableKey}
              className="block break-all font-mono text-sm text-falcon-accent"
            >
              {display(v)}
            </code>
          )
        })}
        {overflow > 0 && (
          <span className="text-xs text-falcon-muted">
            ... {overflow} more
          </span>
        )}
      </div>
    </div>
  )
}

/**
 * Browser-safe verification utility functions.
 *
 * These utilities are designed to work in the browser without Node.js
 * built-ins like `Buffer`. All hex conversions use Uint8Array directly.
 */

import { Option } from "effect"
import type { FalconKeypair, VerificationStep } from "@/services/types"

// ─── Hex conversion ───────────────────────────────────────────────────────────

/**
 * Convert a Uint8Array to a lowercase hex string.
 *
 * Browser-safe: uses Array.from + toString(16) instead of Buffer.from.
 * This works in all modern browsers and in Node.js without any imports.
 */
export function bytesToHex(bytes: Uint8Array): string {
  return Array.from(bytes)
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("")
}

/**
 * Truncate a long hex or felt252 string to `<head>...<tail>` format.
 *
 * If the string is at most `head + tail + 3` characters (including the "..."
 * separator), it is returned unchanged — truncation would not reduce length.
 *
 * @param value - The hex/felt string to truncate.
 * @param head  - Number of characters to keep at the start.
 * @param tail  - Number of characters to keep at the end.
 */
export function truncateHex(value: string, head: number, tail: number): string {
  if (value.length <= head + tail + 3) return value
  return `${value.slice(0, head)}...${value.slice(-tail)}`
}

// ─── Disabled-state derivation ────────────────────────────────────────────────

export interface VerificationDisabledState {
  /** True while any async operation (keygen / sign / verify) is in flight. */
  readonly isBusy: boolean
  /** True when the Generate Keypair button should be enabled. */
  readonly canGenerate: boolean
  /**
   * True when the Sign & Verify button should be enabled.
   *
   * Requires:
   *  - Not busy
   *  - Keypair is Some
   *  - Message is non-empty (after trimming)
   */
  readonly canSign: boolean
}

/** Steps that represent an in-flight async operation. */
const BUSY_STEPS = new Set<VerificationStep["step"]>([
  "generating-keypair",
  "signing",
  "creating-hint",
  "packing",
  "verifying",
])

/**
 * Derive button disabled states from the current atom values.
 *
 * Centralised here (not inline in the component) so it can be unit-tested
 * independently of React rendering.
 */
export function getVerificationDisabledState(args: {
  keypair: Option.Option<FalconKeypair>
  message: string
  step: VerificationStep
}): VerificationDisabledState {
  const { keypair, message, step } = args

  const isBusy = BUSY_STEPS.has(step.step)
  const canGenerate = !isBusy
  const canSign =
    !isBusy && Option.isSome(keypair) && message.trim().length > 0

  return { isBusy, canGenerate, canSign }
}

"use client"

/**
 * VerificationPlayground — interactive Falcon-512 signature demo.
 *
 * Lets the user:
 *   1. Generate a Falcon-512 keypair in-browser via WASM
 *   2. Type a message to sign
 *   3. Run sign → pack public key → verify and see the result with timing
 *
 * Architecture:
 * - Atom state (keypairAtom, verificationStepAtom, messageAtom, etc.) drives
 *   all UI updates — no local useState.
 * - FalconService methods are run via a ManagedRuntime (singleton defined
 *   outside the component) so the WASM layer is loaded at most once.
 * - All Option values are handled via Option.match (never getOrThrow).
 * - Hex display uses bytesToHex (browser-safe, no Buffer.from).
 */

import React, { useCallback } from "react"
import { Cause, Exit, Layer, ManagedRuntime, Option } from "effect"
import { useAtomValue, useAtomSet } from "@effect-atom/atom-react"
import { FalconService } from "@/services/FalconService"
import { WasmRuntimeLive } from "@/services/WasmRuntime"
import {
  keypairAtom,
  messageAtom,
  packedKeyAtom,
  signatureAtom,
  verificationStepAtom,
  wasmStatusAtom,
} from "@/atoms/falcon"
import { HexDisplay } from "./HexDisplay"
import { bytesToHex, getVerificationDisabledState } from "./verification-utils"

// ─── Service runtime (singleton — WASM loaded lazily, at most once) ──────────

const appRuntime = ManagedRuntime.make(
  FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
)
// Intentionally process-lifetime scoped for SPA usage; disposing would drop
// loaded WASM state and force a reload with no functional benefit here.

// ─── Component ────────────────────────────────────────────────────────────────

export function VerificationPlayground(): React.JSX.Element {
  // ── Atom reads ──────────────────────────────────────────────────────────
  const message = useAtomValue(messageAtom)
  const keypair = useAtomValue(keypairAtom)
  const step = useAtomValue(verificationStepAtom)
  const packedKey = useAtomValue(packedKeyAtom)

  // ── Atom writes ─────────────────────────────────────────────────────────
  const setMessage = useAtomSet(messageAtom)
  const setKeypair = useAtomSet(keypairAtom)
  const setStep = useAtomSet(verificationStepAtom)
  const setSignature = useAtomSet(signatureAtom)
  const setPackedKey = useAtomSet(packedKeyAtom)
  const setWasmStatus = useAtomSet(wasmStatusAtom)

  // ── Derived disabled state ───────────────────────────────────────────────
  const { isBusy, canGenerate, canSign } = getVerificationDisabledState({
    keypair,
    message,
    step,
  })

  // ── Handler: Generate Keypair ────────────────────────────────────────────
  const handleGenerateKeypair = useCallback(async () => {
    setStep({ step: "generating-keypair" })
    setPackedKey(Option.none())
    const seed = crypto.getRandomValues(new Uint8Array(32))

    const exit = await appRuntime.runPromiseExit(
      FalconService.generateKeypair(seed),
    )

    if (Exit.isSuccess(exit)) {
      setKeypair(Option.some(exit.value))
      setWasmStatus("ready")
      setStep({ step: "idle" })
    } else {
      const errOpt = Cause.failureOption(exit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Keypair generation failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
    }
  }, [setKeypair, setPackedKey, setStep, setWasmStatus])

  // ── Handler: Sign & Verify ───────────────────────────────────────────────
  const handleSignAndVerify = useCallback(async () => {
    // Extract keypair via Option.match — never getOrThrow
    const kp = Option.match(keypair, {
      onNone: () => null,
      onSome: (k) => k,
    })
    if (!kp) return

    const startTime = Date.now()
    const messageBytes = new TextEncoder().encode(message)

    // ── Sign ──────────────────────────────────────────────────────────────
    setStep({ step: "signing" })
    const signExit = await appRuntime.runPromiseExit(
      FalconService.sign(kp.secretKey, messageBytes),
    )

    if (Exit.isFailure(signExit)) {
      const errOpt = Cause.failureOption(signExit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Signing failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
      return
    }

    const sigResult = signExit.value
    setSignature(Option.some(sigResult))

    // ── Pack Public Key ────────────────────────────────────────────────────
    setStep({ step: "packing" })
    const pkNtt16 = new Uint16Array(kp.publicKeyNtt.length)
    for (let i = 0; i < kp.publicKeyNtt.length; i++) {
      pkNtt16[i] = kp.publicKeyNtt[i]
    }
    const packExit = await appRuntime.runPromiseExit(
      FalconService.packPublicKey(pkNtt16),
    )

    if (Exit.isFailure(packExit)) {
      const errOpt = Cause.failureOption(packExit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Packing failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
      return
    }

    setPackedKey(Option.some(packExit.value))

    // ── Verify ────────────────────────────────────────────────────────────
    setStep({ step: "verifying", substep: "verify" })
    const verifyExit = await appRuntime.runPromiseExit(
      FalconService.verify(kp.verifyingKey, messageBytes, sigResult.signature),
    )

    if (Exit.isFailure(verifyExit)) {
      const errOpt = Cause.failureOption(verifyExit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Verification failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
      return
    }

    const durationMs = Date.now() - startTime
    setStep({ step: "complete", valid: verifyExit.value, durationMs })
  }, [keypair, message, setPackedKey, setSignature, setStep])

  // ── Derived display values ───────────────────────────────────────────────
  // Use bytesToHex (browser-safe, no Buffer.from) + Option.match (no getOrThrow)
  const keypairHexPreview = Option.match(keypair, {
    onNone: () => null,
    onSome: (kp) => "0x" + bytesToHex(kp.verifyingKey),
  })

  const packedKeySlots = Option.match(packedKey, {
    onNone: () => null,
    onSome: (pk) => pk.slots,
  })

  // ── Render ───────────────────────────────────────────────────────────────
  return (
    <section id="verify" className="px-6 py-20 lg:px-8">
      <div className="mx-auto max-w-4xl">
        {/* Section header */}
        <h2 className="text-3xl font-bold tracking-tight text-falcon-text">
          Verification Playground
        </h2>
        <p className="mt-4 text-falcon-muted">
          Generate a Falcon-512 keypair in-browser via WASM, sign a message,
          and verify the signature. All crypto runs locally — no server
          involvement.
        </p>

        <div className="mt-8 space-y-6">
          {/* Message input */}
          <div>
            <label
              htmlFor="message-input"
              className="block text-sm font-medium text-falcon-text"
            >
              Message
            </label>
            <input
              id="message-input"
              type="text"
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              disabled={isBusy}
              placeholder="Enter a message to sign…"
              className="mt-1 w-full rounded-lg border border-falcon-muted/30 bg-falcon-surface px-4 py-2 font-mono text-sm text-falcon-text placeholder-falcon-muted focus:outline-none focus:ring-2 focus:ring-falcon-primary disabled:cursor-not-allowed disabled:opacity-50"
            />
          </div>

          {/* Action buttons */}
          <div className="flex flex-wrap gap-4">
            <button
              onClick={handleGenerateKeypair}
              aria-label="Generate Keypair"
              disabled={!canGenerate}
              className="rounded-lg bg-falcon-primary px-6 py-2.5 text-sm font-semibold text-falcon-text transition-opacity hover:opacity-90 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-falcon-primary disabled:cursor-not-allowed disabled:opacity-50"
            >
              {step.step === "generating-keypair"
                ? "Generating..."
                : "Generate Keypair"}
            </button>

            <button
              onClick={handleSignAndVerify}
              aria-label="Sign and verify message"
              disabled={!canSign}
              className="rounded-lg bg-falcon-accent px-6 py-2.5 text-sm font-semibold text-falcon-text transition-opacity hover:opacity-90 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-falcon-accent disabled:cursor-not-allowed disabled:opacity-50"
            >
              {step.step === "signing" ||
              step.step === "packing" ||
              step.step === "verifying"
                ? "Running…"
                : "Sign & Verify"}
            </button>
          </div>

          {/* Keypair hex preview — uses bytesToHex, no Buffer.from */}
          {keypairHexPreview !== null && (
            <HexDisplay
              label="Verifying Key (preview)"
              value={keypairHexPreview}
              truncate={{ head: 18, tail: 8 }}
            />
          )}

          {/* Packed public key — 29 felt252 slots */}
          {packedKeySlots !== null && (
            <HexDisplay
              label="Packed Public Key (29 felt252 slots)"
              value={packedKeySlots}
              maxRows={29}
              truncate={{ head: 18, tail: 8 }}
            />
          )}

          {/* Success result */}
          {step.step === "complete" && (
            <div
              role="status"
              aria-live="polite"
              className={`rounded-xl border p-4 ${
                step.valid
                  ? "border-falcon-success/30 bg-falcon-success/10"
                  : "border-falcon-error/30 bg-falcon-error/10"
              }`}
            >
              <div className="flex items-center gap-3">
                <span
                  className={`text-xl font-bold ${
                    step.valid ? "text-falcon-success" : "text-falcon-error"
                  }`}
                >
                  {step.valid ? "✓" : "✗"}
                </span>
                <span className="font-semibold text-falcon-text">
                  {step.valid ? "Signature valid" : "Signature invalid"}
                </span>
                <span className="ml-auto text-sm text-falcon-muted">
                  {step.durationMs}ms
                </span>
              </div>
            </div>
          )}

          {/* Error state */}
          {step.step === "error" && (
            <div
              role="alert"
              aria-live="polite"
              className="rounded-xl border border-falcon-error/30 bg-falcon-error/10 p-4"
            >
              <div className="flex items-start gap-3">
                <span className="text-xl font-bold text-falcon-error">✗</span>
                <div className="flex-1">
                  <p className="font-semibold text-falcon-error">Error</p>
                  <p className="mt-1 break-all text-sm text-falcon-muted">
                    {step.message}
                  </p>
                </div>
                <button
                  onClick={() => setStep({ step: "idle" })}
                  aria-label="Reset verification state"
                  className="ml-auto rounded-lg border border-falcon-muted/30 px-3 py-1 text-xs text-falcon-muted hover:bg-falcon-surface"
                >
                  Try Again
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </section>
  )
}

"use client"

import React, { useCallback, useEffect, useMemo, useRef, useState } from "react"
import { useAtomSet, useAtomValue } from "@effect-atom/atom-react"
import { Cause, Exit, Layer, ManagedRuntime, Option } from "effect"
import { keypairAtom } from "@/atoms/falcon"
import {
  deployStepAtom,
  deployedAddressAtom,
  deployTxHashAtom,
  networkAtom,
} from "@/atoms/starknet"
import { NETWORKS } from "@/config/networks"
import type { NetworkConfig } from "@/config/networks"
import { FalconService } from "@/services/FalconService"
import { StarknetService } from "@/services/StarknetService"
import { WasmRuntimeLive } from "@/services/WasmRuntime"
import type { PreparedAccountDeploy } from "./accountDeployPipeline"
import {
  deployAccountEffect,
  prepareAccountDeployEffect,
} from "./accountDeployPipeline"

function createDeployRuntime(config: NetworkConfig) {
  return ManagedRuntime.make(
    Layer.mergeAll(
      FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
      StarknetService.make(config.rpcUrl, config.classHash),
    ),
  )
}

const extractFailureMessage = <A, E extends { readonly message: string }>(
  exit: Exit.Exit<A, E>,
  fallback: string,
): string => {
  if (Exit.isSuccess(exit)) {
    return fallback
  }
  const failure = Cause.failureOption(exit.cause)
  return Option.match(failure, {
    onNone: () => fallback,
    onSome: (error) => error.message,
  })
}

export function AccountDeployFlow(): React.JSX.Element {
  const keypair = useAtomValue(keypairAtom)
  const deployStep = useAtomValue(deployStepAtom)
  const setKeypair = useAtomSet(keypairAtom)
  const setDeployStep = useAtomSet(deployStepAtom)
  const setDeployedAddress = useAtomSet(deployedAddressAtom)
  const setDeployTxHash = useAtomSet(deployTxHashAtom)
  const networkId = useAtomValue(networkAtom)
  const networkConfig = NETWORKS[networkId]

  // Runtime ref — rebuild synchronously when network changes
  const deployRuntimeRef = useRef(createDeployRuntime(networkConfig))
  const prevNetworkRef = useRef(networkId)
  if (prevNetworkRef.current !== networkId) {
    prevNetworkRef.current = networkId
    deployRuntimeRef.current = createDeployRuntime(networkConfig)
  }

  const [privateKey, setPrivateKey] = useState("")
  const [preparedDeploy, setPreparedDeploy] =
    useState<Option.Option<PreparedAccountDeploy>>(Option.none())
  const [balance, setBalance] = useState<bigint | null>(null)

  // Reset deploy state when network changes
  useEffect(() => {
    setDeployStep({ step: "idle" })
    setPreparedDeploy(Option.none())
    setBalance(null)
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [networkId])

  const hasKeypair = Option.isSome(keypair)

  useEffect(() => {
    if (deployStep.step !== "awaiting-funds") {
      setBalance(null)
      return
    }

    let cancelled = false

    const poll = async () => {
      const exit = await deployRuntimeRef.current.runPromiseExit(
        StarknetService.getBalance(deployStep.address),
      )
      if (!cancelled && Exit.isSuccess(exit)) {
        setBalance(exit.value)
      }
    }

    poll()
    const interval = setInterval(poll, 5000)
    return () => {
      cancelled = true
      clearInterval(interval)
    }
  }, [deployStep])

  const handlePrepare = useCallback(async () => {
    setDeployStep({ step: hasKeypair ? "packing" : "generating-keypair" })
    setDeployTxHash(Option.none())
    setDeployedAddress(Option.none())
    setPreparedDeploy(Option.none())

    const prepareExit = await deployRuntimeRef.current.runPromiseExit(
      prepareAccountDeployEffect({
        privateKey,
        existingKeypair: keypair,
      }),
    )

    if (Exit.isFailure(prepareExit)) {
      setDeployStep({
        step: "error",
        message: extractFailureMessage(prepareExit, "Failed to prepare deployment"),
      })
      return
    }

    const prepared = prepareExit.value
    setPreparedDeploy(Option.some(prepared))
    setKeypair(Option.some(prepared.keypair))
    setDeployStep({ step: "computing-address" })
    setDeployStep({ step: "awaiting-funds", address: prepared.address })
  }, [
    hasKeypair,
    keypair,
    privateKey,
    setDeployStep,
    setDeployTxHash,
    setDeployedAddress,
    setKeypair,
  ])

  const handleDeploy = useCallback(async () => {
    const prepared = Option.match(preparedDeploy, {
      onNone: () => null,
      onSome: (value) => value,
    })
    if (prepared === null) {
      setDeployStep({
        step: "error",
        message: "Prepare the deployment before submitting.",
      })
      return
    }

    setDeployStep({ step: "deploying", address: prepared.address })
    const deployExit = await deployRuntimeRef.current.runPromiseExit(
      deployAccountEffect({
        address: prepared.address,
        packedPublicKey: prepared.packedPublicKey,
        privateKey: prepared.privateKey,
        salt: prepared.salt,
        requiredBalance: 1n,
      }),
    )

    if (Exit.isFailure(deployExit)) {
      setDeployStep({
        step: "error",
        message: extractFailureMessage(deployExit, "Account deployment failed"),
      })
      return
    }

    setDeployTxHash(Option.some(deployExit.value.txHash))
    setDeployedAddress(Option.some(deployExit.value.address))
    setDeployStep({
      step: "deployed",
      txHash: deployExit.value.txHash,
      address: deployExit.value.address,
    })
  }, [preparedDeploy, setDeployStep, setDeployTxHash, setDeployedAddress])

  const handleReset = useCallback(() => {
    setPreparedDeploy(Option.none())
    setDeployTxHash(Option.none())
    setDeployedAddress(Option.none())
    setDeployStep({ step: "idle" })
  }, [setDeployStep, setDeployTxHash, setDeployedAddress])

  const stepFlags = useMemo(() => {
    const stepName = deployStep.step

    const step1Complete =
      hasKeypair ||
      stepName === "packing" ||
      stepName === "computing-address" ||
      stepName === "awaiting-funds" ||
      stepName === "deploying" ||
      stepName === "deployed"

    const step2Complete =
      stepName === "computing-address" ||
      stepName === "awaiting-funds" ||
      stepName === "deploying" ||
      stepName === "deployed"

    const step3Complete =
      stepName === "awaiting-funds" ||
      stepName === "deploying" ||
      stepName === "deployed"

    const step4Complete = stepName === "deploying" || stepName === "deployed"
    const step5Complete = stepName === "deployed"

    return {
      step1Active: stepName === "generating-keypair",
      step2Active: stepName === "packing",
      step3Active: stepName === "computing-address",
      step4Active: stepName === "awaiting-funds",
      step5Active: stepName === "deploying",
      step1Complete,
      step2Complete,
      step3Complete,
      step4Complete,
      step5Complete,
    }
  }, [deployStep.step, hasKeypair])

  const liveStatus = useMemo(() => {
    switch (deployStep.step) {
      case "idle":
        return "Account deploy flow is idle."
      case "generating-keypair":
        return "Generating Falcon keypair."
      case "packing":
        return "Packing Falcon public key."
      case "computing-address":
        return "Computing Starknet deploy address."
      case "awaiting-funds":
        return `Waiting for funds at ${deployStep.address}.`
      case "deploying":
        return "Deploying account transaction."
      case "deployed":
        return `Account deployed with transaction hash ${deployStep.txHash}.`
      case "error":
        return deployStep.message
    }
  }, [deployStep])

  return (
    <section id="deploy" className="px-6 py-20 lg:px-8">
      <div className="mx-auto max-w-4xl">
        <h2 className="text-3xl font-bold tracking-tight text-falcon-text">Account Deploy Flow</h2>
        <p className="mt-4 text-falcon-muted">
          Deploy a Falcon-powered account to Starknet {networkConfig.name} with the same keypair used in
          the verification playground.
        </p>
        <p className="sr-only" aria-live="polite">
          {liveStatus}
        </p>

        <div className="mt-8 space-y-4">
          <DeployStepIndicator
            number={1}
            title="Generate Keypair"
            description="Create or reuse a Falcon-512 keypair."
            active={stepFlags.step1Active}
            complete={stepFlags.step1Complete}
          />
          <DeployStepIndicator
            number={2}
            title="Pack Public Key"
            description="Compress public key coefficients into 29 felt252 slots."
            active={stepFlags.step2Active}
            complete={stepFlags.step2Complete}
          />
          <DeployStepIndicator
            number={3}
            title="Compute Address"
            description="Compute the account counterfactual address."
            active={stepFlags.step3Active}
            complete={stepFlags.step3Complete}
          />
          <DeployStepIndicator
            number={4}
            title="Fund Account"
            description="Send STRK to the pre-computed address."
            active={stepFlags.step4Active}
            complete={stepFlags.step4Complete}
          >
            {deployStep.step === "awaiting-funds" && (
              <div className="mt-3 space-y-3">
                <div className="rounded-lg bg-falcon-bg p-3">
                  <p className="text-xs uppercase tracking-wide text-falcon-muted">Send STRK to</p>
                  <div className="mt-1 flex items-center gap-2">
                    <code className="flex-1 break-all font-mono text-sm text-falcon-accent">
                      {deployStep.address}
                    </code>
                    <button
                      onClick={() => navigator.clipboard.writeText(deployStep.address)}
                      className="shrink-0 rounded border border-falcon-muted/30 px-2 py-1 text-xs text-falcon-muted hover:bg-falcon-surface"
                      title="Copy address"
                    >
                      Copy
                    </button>
                  </div>
                </div>
                {networkConfig.isTestnet && (
                  <a
                    href="https://starknet-faucet.vercel.app/"
                    target="_blank"
                    rel="noreferrer noopener"
                    className="inline-block text-sm text-falcon-accent hover:underline"
                  >
                    Get testnet STRK from the Starknet Faucet &rarr;
                  </a>
                )}
                {balance !== null && (
                  <p className="text-sm text-falcon-muted">
                    Current balance:{" "}
                    <span className={balance > 0n ? "text-falcon-success" : "text-falcon-muted"}>
                      {(Number(balance) / 1e18).toFixed(4)} STRK
                    </span>
                    {balance > 0n && (
                      <span className="ml-2 text-falcon-success">— Ready to deploy!</span>
                    )}
                  </p>
                )}
              </div>
            )}
          </DeployStepIndicator>
          <DeployStepIndicator
            number={5}
            title="Deploy"
            description="Broadcast and confirm deploy transaction."
            active={stepFlags.step5Active}
            complete={stepFlags.step5Complete}
          />
        </div>

        <div className="mt-8 space-y-3">
          <label htmlFor="deploy-private-key" className="block text-sm font-medium text-falcon-text">
            Deployer Private Key
          </label>
          <input
            id="deploy-private-key"
            type="password"
            autoComplete="off"
            value={privateKey}
            onChange={(event) => setPrivateKey(event.target.value)}
            placeholder="0x..."
            className="w-full rounded-lg border border-falcon-muted/30 bg-falcon-surface px-4 py-2 font-mono text-sm text-falcon-text placeholder-falcon-muted focus:outline-none focus:ring-2 focus:ring-falcon-primary"
          />

          {deployStep.step === "idle" && (
            <button
              onClick={handlePrepare}
              className="rounded-lg bg-falcon-primary px-6 py-2.5 text-sm font-semibold text-falcon-text hover:opacity-90"
            >
              Prepare Deploy
            </button>
          )}

          {deployStep.step === "awaiting-funds" && (
            <button
              onClick={handleDeploy}
              className="rounded-lg bg-falcon-accent px-6 py-2.5 text-sm font-semibold text-falcon-text hover:opacity-90"
            >
              Deploy Account
            </button>
          )}
        </div>

        {deployStep.step === "deployed" && (
          <div
            role="status"
            aria-live="polite"
            className="mt-6 rounded-xl border border-falcon-success/30 bg-falcon-success/10 p-5"
          >
            <h3 className="font-semibold text-falcon-success">Account Deployed</h3>
            <p className="mt-2 break-all font-mono text-xs text-falcon-text">
              Address: {deployStep.address}
            </p>
            <p className="mt-1 break-all font-mono text-xs text-falcon-text">Tx: {deployStep.txHash}</p>
            <a
              href={`${networkConfig.explorerBaseUrl}/tx/${deployStep.txHash}`}
              target="_blank"
              rel="noreferrer noopener"
              className="mt-3 inline-block text-sm text-falcon-accent hover:underline"
            >
              View on Voyager
            </a>
          </div>
        )}

        {deployStep.step === "error" && (
          <div
            role="alert"
            aria-live="polite"
            className="mt-6 rounded-xl border border-falcon-error/30 bg-falcon-error/10 p-5"
          >
            <p className="text-sm text-falcon-error">{deployStep.message}</p>
            <button
              onClick={handleReset}
              className="mt-3 rounded-lg border border-falcon-muted/30 px-3 py-1 text-xs text-falcon-muted hover:bg-falcon-surface"
            >
              Try Again
            </button>
          </div>
        )}
      </div>
    </section>
  )
}

interface DeployStepIndicatorProps {
  readonly number: number
  readonly title: string
  readonly description: string
  readonly active: boolean
  readonly complete: boolean
  readonly children?: React.ReactNode
}

function DeployStepIndicator({
  number,
  title,
  description,
  active,
  complete,
  children,
}: DeployStepIndicatorProps): React.JSX.Element {
  const containerClass = active
    ? "border-falcon-primary ring-2 ring-falcon-primary/20"
    : complete
      ? "border-falcon-success/40"
      : "border-falcon-muted/20"

  const badgeClass = complete
    ? "bg-falcon-success/20 text-falcon-success"
    : active
      ? "bg-falcon-primary/20 text-falcon-primary"
      : "bg-falcon-muted/10 text-falcon-muted"

  return (
    <div className={`rounded-xl border bg-falcon-surface p-4 transition-all ${containerClass}`}>
      <div className="flex items-center gap-3">
        <span className={`flex h-8 w-8 items-center justify-center rounded-full text-sm font-bold ${badgeClass}`}>
          {complete ? "✓" : number}
        </span>
        <div>
          <h3 className="font-semibold text-falcon-text">{title}</h3>
          <p className="text-sm text-falcon-muted">{description}</p>
        </div>
      </div>
      {children}
    </div>
  )
}

